class NetworkManager {
    var onComplete: (() -> Void)?

    func fetchData() {
        // 使用 weak 捕获避免循环引用
        DispatchQueue.global().async { [weak self] in
            guard let self = self else { return }
            print("数据加载完成")
            self.onComplete?()
        }
    }

    func captureExample() {
        var x = 10
        let closure = { [x] in
            print("x 的值: \(x)")  // 输出 10，即使之后 x 改变
        }
        x = 20
        closure()  // 仍然输出 10
    }
}

